import threading
from dataclasses import dataclass, field

@dataclass
class AbortSignal:
    """Thread-safe abort flag. Set by any kill-switch trigger; checked before tool calls."""
    _event: threading.Event = field(default_factory=threading.Event)
    reason: str = ""

    def abort(self, reason: str = "kill switch activated") -> None:
        self.reason = reason
        self._event.set()

    @property
    def is_set(self) -> bool:
        return self._event.is_set()

class AbortError(RuntimeError):
    """Raised when execution is halted via a kill switch."""

def tool_guard(signal: AbortSignal, tool_name: str):
    """Call before every tool execution. Raises AbortError if signal is set."""
    if signal.is_set:
        raise AbortError(
            f"Execution halted before '{tool_name}': {signal.reason}"
        )

# Usage in the execution loop
abort = AbortSignal()

def safe_execute(tool_name: str, arguments: dict, executor) -> dict:
    tool_guard(abort, tool_name)       # check before
    result = executor(tool_name, arguments)
    tool_guard(abort, tool_name)       # check after (long-running tools)
    return result

import concurrent.futures, threading

class AgentOrchestrator:
    def __init__(self):
        self._abort = AbortSignal()
        self._futures: list[concurrent.futures.Future] = []
        self._lock = threading.Lock()

    def submit(self, agent_fn, *args, **kwargs) -> concurrent.futures.Future:
        """Submit an agent task. The task receives the shared abort signal."""
        executor = concurrent.futures.ThreadPoolExecutor(max_workers=1)
        future = executor.submit(agent_fn, *args, signal=self._abort, **kwargs)
        with self._lock:
            self._futures.append(future)
        return future

    def halt(self, reason: str = "orchestrator halt") -> dict:
        """
        Trigger halt on all running agents.
        Returns when all agents have exited (or timed out).
        """
        self._abort.abort(reason)
        results = {"halted": 0, "timed_out": 0}

        for future in self._futures:
            try:
                future.result(timeout=30.0)
            except (AbortError, concurrent.futures.CancelledError):
                results["halted"] += 1
            except concurrent.futures.TimeoutError:
                results["timed_out"] += 1
                future.cancel()

        return results

from enum import Enum

class AbortMode(Enum):
    GRACEFUL = "graceful"
    HARD     = "hard"

class AbortSignal:
    def __init__(self):
        self._mode: AbortMode | None = None
        self.reason: str = ""

    def abort(self, reason: str = "", mode: AbortMode = AbortMode.GRACEFUL) -> None:
        self._mode = mode
        self.reason = reason

    @property
    def is_set(self) -> bool:
        return self._mode is not None

    @property
    def is_hard(self) -> bool:
        return self._mode == AbortMode.HARD

def cancellable_loop_with_cleanup(messages, model_call, tool_executor,
                                   signal: AbortSignal,
                                   cleanup_fn=None) -> str | None:
    try:
        for _ in range(100):
            if signal.is_set:
                if signal.is_hard:
                    raise AbortError(f"Hard abort: {signal.reason}")
                # Graceful: run cleanup and return partial result
                if cleanup_fn:
                    cleanup_fn()
                return None

            response = model_call(messages)
            if not response.tool_calls:
                return response.content
            for call in response.tool_calls:
                tool_executor(call.name, call.arguments)
    except AbortError:
        raise
    except Exception as exc:
        if signal.is_set and signal.is_hard:
            raise AbortError(f"Hard abort during exception: {exc}") from exc
        raise
